#include<bits/stdc++.h>
using namespace std;
const int N=16005;
int a[N],dp[N],n;
long long ans=-0x3f3f3f3f;
vector<int> g[N];
int dfs(int x,int y)
{
    int cnt=0;
    for(int i=0;i<g[x].size();i++)
    {
        if(g[x][i]==y) continue;
        int t=dfs(g[x][i],x);
        if(t>0) cnt+=t;
    }
    cnt+=a[x];
    ans=max(ans,(long long)cnt);
    return cnt;
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        cin>>x>>y;
        g[x].push_back(y);
        g[y].push_back(x);
    }
    dfs(1,0);
    cout<<ans;
    return 0;
}
